import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // --- Quote: base premiums for single main items ---
  it.todo("quote: empty item list → premium 5 G (only the processing fee)");
  it.todo("quote: single sword (steel, ench 3) → premium 105 G (100 base + 5 fee)");
  it.todo("quote: single amulet → premium 65 G (60 base + 5 fee)");
  it.todo("quote: single staff → premium 85 G (80 base + 5 fee)");
  it.todo("quote: single potion → premium 45 G (40 base + 5 fee)");

  // --- Quote: components and building blocks ---
  it.todo("quote: 2 runes → base 50 G → premium 55 G");
  it.todo("quote: 3 runes → base 60 G (block applies) → premium 65 G");
  it.todo("quote: 4 runes → base 100 G (no block, exactly 3 required) → premium 105 G");
  it.todo("quote: 7 runes → base 175 G (one block of 3 + 4 singles: 60+100) → premium 180 G");
  it.todo("quote: 2 runes + 1 moonstone → base 75 G (no block, different types) → premium 80 G");
  it.todo("quote: 3 runes + 3 moonstones → base 120 G (two separate blocks) → premium 125 G");

  // --- Quote: item-specific modifiers ---
  it.todo("quote: cursed sword (ench 3) → base 100 + 50 curse = 150 → premium 155 G");
  it.todo("quote: sword with exactly enchantment 5 → +30% high-enchantment surcharge (100 + 30 = 130) → premium 135 G");
  it.todo("quote: sword with enchantment 4 → no high-enchantment surcharge → premium 105 G");
  it.todo("quote: cursed sword with enchantment 5 → both surcharges (100 + 50 + 30 = 180) → premium 185 G");

  // --- Quote: policy-wide modifiers ---
  it.todo("quote: loyalty discount applies at exactly 2 years (-20% of policy base)");
  it.todo("quote: first insurance surcharge (+10%) applies to a first contract");
  it.todo("quote: follow-up contract discount (-15%) applies to the second quote in a scenario");

  // --- Quote: modifier scope on multi-item policies ---
  it.todo("quote: cursed sword (100) + plain amulet (60) → base 160; curse adds 50 (50% of sword) → 210 before further modifiers and fee");

  // --- Quote: rounding ---
  it.todo("quote: premium of 197.5 G rounds UP to 198 G (MHPCO's favor)");

  // --- Quote: integration examples ---
  it.todo("quote integration: newcomer (0 yrs, first contract) cursed sword (steel, ench 3) → 165 G (100 + 50 curse + 10 first + 5 fee)");
  it.todo("quote integration: long-standing (3 yrs), 2nd quote, cursed sword (steel, ench 7) → 160 G (100 + 50 + 30 - 20 loyalty + 10 first - 15 follow-up + 5 fee)");

  // --- Claim: standard reimbursement ---
  it.todo("claim: regular sword (steel, ench 3), damage 500 → payout 400 G (full minus 100 deductible)");
  it.todo("claim: rune (value 250), damage 200 → payout 100 G (full minus 100 deductible, no special clause)");

  // --- Claim: special clauses ---
  it.todo("claim: high-enchantment (≥8) sword, ench 8, dragon material, damage 1000 → payout 400 G (50% rule, then deductible)");
  it.todo("claim: dragon-material sword, ench 9, damage 1000 → payout 400 G (both clauses, 50% wins, then deductible)");
  it.todo("claim: dragon-material sword, ench 5, damage 800 → payout 700 G (dragon full reimbursement, then deductible)");
  it.todo("claim: steel sword, ench 9, damage 1000 → payout 400 G (high-enchantment 50% first, then deductible)");

  // --- Claim: deductible per damage event ---
  it.todo("claim: dragon attack damages sword (500) and amulet (300) → payout 600 G (deductible once per item)");

  // --- Claim: cap and insurance sum ---
  it.todo("claim: sword + amulet → insurance sum 1600, cap 3200");
  it.todo("claim: two swords → insurance sum 2000, cap 4000; two damage entries each own deductible");
  it.todo("claim: cursed sword → cap 2000 based on unmodified insurance value (modifiers do not raise cap)");
  it.todo("claim: sword + 3 runes (block) → insurance sum 1750 (block discount affects premium only, not insurance sum)");

  // --- Claim: cap exhaustion across successive claims ---
  it.todo("claim: sword (cap 2000), first claim 1500 → payout 1400, remaining cap 600");
  it.todo("claim: sword (cap 2000), second claim 1500 → payout 600 (reduced to remaining cap), remaining cap 0");

  // --- Claim: rounding ---
  it.todo("claim: payout of 350.5 G rounds DOWN to 350 G (MHPCO's favor)");

  // --- Error / edge cases ---
  it.todo("error: quote includes an unknown item type (e.g. broomstick) → throws / rejected");
  it.todo("error: claim references a damage item not in the policy (e.g. amulet when only sword insured) → rejected");
  it.todo("error: claim has more damage entries of a type than the policy covers (two sword damages, one sword insured) → rejected");
  it.todo("error: claim has a damage entry with negative amount (-200) → rejected");
});

