const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_PREMIUM = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_TYPES = ["rune"];

const isComponent = (type: string): boolean => COMPONENT_TYPES.includes(type);

const componentGroupPremium = (count: number): number =>
  count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PREMIUM
    : count * COMPONENT_PREMIUM;

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const totalBasePremium = (items: Item[]): number => {
  let total = 0;
  for (const [type, count] of countByType(items)) {
    total += isComponent(type)
      ? componentGroupPremium(count)
      : (BASE_PREMIUMS[type] ?? 0) * count;
  }
  return total;
};

export const quote = (input: QuoteInput): number =>
  totalBasePremium(input.items) + PROCESSING_FEE;

