export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteInput {
  customer: Customer;
  items: Item[];
}

const PROCESSING_FEE = 5;
const BLOCK_SIZE = 3;
const RUNE_BLOCK_PREMIUM = 60;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const unitPriceFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;

const isRune = (item: Item): boolean => item.type === "rune";

const isMainItem = (item: Item): boolean => !isRune(item);

const RUNE_UNIT_PRICE = unitPriceFor("rune");

const runeBasePremium = (runeCount: number): number =>
  runeCount === BLOCK_SIZE ? RUNE_BLOCK_PREMIUM : runeCount * RUNE_UNIT_PRICE;

const sumUnitPrices = (items: Item[]): number =>
  items.reduce((sum, item) => sum + unitPriceFor(item.type), 0);

const countRunes = (items: Item[]): number => items.filter(isRune).length;

const totalBasePremium = (items: Item[]): number =>
  sumUnitPrices(items.filter(isMainItem)) + runeBasePremium(countRunes(items));

export const quote = (input: QuoteInput): number =>
  totalBasePremium(input.items) + PROCESSING_FEE;

export const claim = (...args: unknown[]): unknown => {
  return undefined; // Not yet implemented
};

