export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteInput {
  customer: Customer;
  items: Item[];
}

const PROCESSING_FEE = 5;
const BLOCK_SIZE = 3;
const RUNE_BLOCK_PREMIUM = 60;
const FIRST_INSURANCE_RATE = 0.1;
const LOYALTY_RATE = 0.2;
const LOYALTY_MIN_YEARS = 2;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

const unitPriceFor = (type: string): number => BASE_PREMIUMS[type] ?? 0;

const isRune = (item: Item): boolean => item.type === "rune";

const isMainItem = (item: Item): boolean => !isRune(item);

const runeBasePremium = (runeCount: number): number =>
  runeCount === BLOCK_SIZE
    ? RUNE_BLOCK_PREMIUM
    : runeCount * unitPriceFor("rune");

const sumUnitPrices = (items: Item[]): number =>
  items.reduce((sum, item) => sum + unitPriceFor(item.type), 0);

const countRunes = (items: Item[]): number => items.filter(isRune).length;

const totalBasePremium = (items: Item[]): number =>
  sumUnitPrices(items.filter(isMainItem)) + runeBasePremium(countRunes(items));

const firstInsuranceSurcharge = (policyBase: number): number =>
  policyBase * FIRST_INSURANCE_RATE;

const isLoyal = (customer: Customer): boolean =>
  customer.yearsWithMHPCO >= LOYALTY_MIN_YEARS;

const loyaltyDiscount = (policyBase: number, customer: Customer): number =>
  isLoyal(customer) ? policyBase * LOYALTY_RATE : 0;

export const quote = (input: QuoteInput): number => {
  const policyBase = totalBasePremium(input.items);
  const premiumBeforeFee =
    policyBase +
    firstInsuranceSurcharge(policyBase) -
    loyaltyDiscount(policyBase, input.customer);
  return Math.ceil(premiumBeforeFee + PROCESSING_FEE);
};

export const claim = (...args: unknown[]): unknown => {
  return undefined;
};

